@startuml
abstract class Payment {
  amount
  date
}

class StateChapter
class DistrictChapter
class Member {
  status
}
class MembershipApplication {
  status
}
interface NotificationContract
class Committee
class Mandate {
  termOfOffice
}
class Campaign
class Deployment {
  hours
}
class MembershipFeePayment {
  contributionYear
}
class Donation

enum MemberStatus {
  active
  passive
  resigned
}

enum ApplicationStatus {
  received
  reviewed
  accepted
  rejected
}

StateChapter "1" *-- "0..*" DistrictChapter : chapters
DistrictChapter "1" -- "0..*" Member : members
Member ..|> NotificationContract
DistrictChapter "1" -- "0..*" MembershipApplication : applications
MembershipApplication "1" -- "1" Member : emerges
Committee "1" *-- "0..*" Mandate : mandates
Mandate "0..*" -- "1" Member : holder
DistrictChapter "1" -- "0..*" Campaign : campaigns
Campaign "1" -- "0..*" Deployment : deployments
Member "1" -- "0..*" Deployment : participates
MembershipFeePayment --|> Payment
Donation --|> Payment
Donation "0..*" -- "0..1" Campaign : earmark
Payment "0..*" -- "1" Member : payer
Member -- MemberStatus
MembershipApplication -- ApplicationStatus
@enduml

